// AutoCloseableを実装したカスタムリソース
class MyResource implements AutoCloseable {
    String name;
    MyResource(String name) {
        this.name = name;
        System.out.println(name + " opened");
    }
    @Override
    public void close() throws Exception {
        System.out.println(name + " closed");
    }
}

// try-with-resourcesで使用
try (MyResource r = new MyResource("Resource1")) {
    System.out.println("Using " + r.name);
}
// 出力:
// Resource1 opened
// Using Resource1
// Resource1 closed

class Res implements AutoCloseable {
    String name;
    Res(String name) {
        this.name = name;
        System.out.println(name + " opened");
    }
    public void close() {
        System.out.println(name + " closed");
    }
}

try (Res r1 = new Res("A"); Res r2 = new Res("B"); Res r3 = new Res("C")) {
    System.out.println("Processing");
}
// 出力:
// A opened
// B opened
// C opened
// Processing
// C closed（逆順）
// B closed
// A closed

