class FailClose implements AutoCloseable {
    public void close() {
        throw new RuntimeException("close error");
    }
}

try (FailClose fc = new FailClose()) {
    throw new RuntimeException("try error");
} catch (RuntimeException e) {
    System.out.println("Primary: " + e.getMessage());
    for (Throwable t : e.getSuppressed()) {
        System.out.println("Suppressed: " + t.getMessage());
    }
}
// 出力:
// Primary: try error
// Suppressed: close error

class Res implements AutoCloseable {
    String name;
    Res(String name) { this.name = name; }
    public void close() {
        throw new RuntimeException(name + " close fail");
    }
}

try (Res a = new Res("A"); Res b = new Res("B")) {
    throw new RuntimeException("main error");
} catch (RuntimeException e) {
    System.out.println("Primary: " + e.getMessage());
    for (Throwable t : e.getSuppressed()) {
        System.out.println("Suppressed: " + t.getMessage());
    }
}
// 出力:
// Primary: main error
// Suppressed: B close fail（逆順でBが先にclose）
