public void process() {
    Exception suppressed = null;
    Resource r = acquire();
    try {
        r.use();
    } catch (Exception e) {
        suppressed = e;
    } finally {
        try { r.close(); }
        catch (Exception e2) {
            if (suppressed != null)
                suppressed.addSuppressed(e2);
        }
    }
}

