} catch (IOException | SQLException e) {
    // OK：継承関係がない
    // e = new IOException(); // コンパイルエラー：再代入不可
    System.out.println(e.getMessage());
}

// コンパイルエラーの例
try {
    // ...
} catch (FileNotFoundException | IOException e) { // エラー！
    // FileNotFoundExceptionはIOExceptionのサブクラス
}

// 単一catchは再代入可能
try {
    // ...
} catch (IOException e) {
    e = new IOException("wrapped"); // OK
}

// Java 7以降の再スロー型推論
public void process() throws IOException, SQLException {
    try {
        // IOExceptionまたはSQLExceptionをスローする可能性
        callMethod();
    } catch (Exception e) {
        // eの型はExceptionだが、コンパイラは実際のスロー型を追跡
        // throws句にはIOException, SQLExceptionのみ宣言すればOK
        System.out.println("Error: " + e.getMessage());
        throw e; // コンパイラがより具体的な型として扱う
    }
}

// 再代入すると型推論が効かない
public void process2() throws Exception { // Exceptionが必要
    try {
        callMethod();
    } catch (Exception e) {
        e = new Exception("changed"); // 再代入
        throw e; // Exceptionとしてしか推論できない
    }
}

public class ServiceException extends Exception {
    public ServiceException(String msg, Throwable cause) {
        super(msg, cause);
    }
}

public void processData() throws ServiceException {
    try {
        // データベース操作
        connectDB();
    } catch (SQLException e) {
        // SQLExceptionをServiceExceptionでラップ
        throw new ServiceException("データ処理エラー", e);
    }
}

// 呼び出し側で原因を取得
try {
    processData();
} catch (ServiceException e) {
    System.out.println(e.getMessage()); // データ処理エラー
    System.out.println(e.getCause());   // java.sql.SQLException: ...
}

